input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    if n == 1:
        print(1)
        return

    d = [abs(a[i+1] - a[i]) for i in range(n-1)]

    # Find longest subarray of d with gcd >= 2
    # For each r, maintain list of (gcd, start_index) for subarrays ending at r
    best = 1  # at minimum, single element is friend group of size 1

    # prev: list of (gcd_value, leftmost_start)
    prev = []
    for r in range(len(d)):
        curr = []
        for g, start in prev:
            ng = gcd(g, d[r])
            if curr and curr[-1][0] == ng:
                pass  # same gcd, start is already the leftmost
            else:
                curr.append((ng, start))
        if curr and curr[-1][0] == d[r]:
            curr[-1] = (d[r], curr[-1][1])
        else:
            curr.append((d[r], r))

        for g, start in curr:
            if g >= 2:
                length = r - start + 1  # length in d array
                best = max(best, length + 1)

        prev = curr

    print(best)

t = int(input())
for _ in range(t):
    solve()

